// keywords.json 과 동기화된 우선순위 키워드. 간단히 여기서 하드코딩하거나
// HTTP GET 으로 우리 /config 엔드포인트에서 가져오도록 바꿀 수 있습니다.
const queries = [
  { q: 'photoresist resin polymer',       weight: 10, hint: 'resin' },
  { q: 'EUV photoresist',                 weight: 10, hint: 'pr' },
  { q: 'chemically amplified resist',     weight: 9,  hint: 'pr' },
  { q: 'metal oxide photoresist',         weight: 8,  hint: 'pr' },
  { q: 'photoresist development TMAH',    weight: 7,  hint: 'develop_etch' },
  { q: 'EUV lithography resist outgassing', weight: 7, hint: 'pr' },
  { q: 'line edge roughness photoresist', weight: 6,  hint: 'pr' },
  { q: 'photo acid generator PAG',        weight: 6,  hint: 'pr' },
  { q: 'dry etching selectivity semiconductor', weight: 5, hint: 'develop_etch' },
  { q: 'negative tone development',       weight: 5,  hint: 'develop_etch' },
  { q: 'molecular glass resist',          weight: 5,  hint: 'resin' },
  { q: 'novel photoresist',               weight: 3,  hint: 'novel_idea' }
];
return queries.map(item => ({ json: item }));

// 세 소스의 응답을 동일 PaperRef 형식으로 정규화 + 머지 + 중복 제거.
// 각 소스 노드에서 넘어온 배치를 모두 모아서 처리.
const items = $input.all();
const out = [];

function push(ref) {
  if (!ref || !ref.title) return;
  out.push(ref);
}

for (const it of items) {
  const src = it.json?.__srcName || '';   // 보조용 (세팅 안 돼도 동작)
  const data = it.json;
  // --- arXiv (XML 텍스트) ---
  if (typeof data === 'string' && data.includes('<feed')) {
    const xml = data;
    const entryRe = /<entry>[\s\S]*?<\/entry>/g;
    const matches = xml.match(entryRe) ?? [];
    for (const e of matches) {
      const idM   = /<id>([^<]+)<\/id>/.exec(e);
      const ttlM  = /<title>([\s\S]*?)<\/title>/.exec(e);
      const sumM  = /<summary>([\s\S]*?)<\/summary>/.exec(e);
      const pubM  = /<published>([^<]+)<\/published>/.exec(e);
      const pdfM  = /<link[^>]*title="pdf"[^>]*href="([^"]+)"/.exec(e);
      const htmlM = /<link[^>]*rel="alternate"[^>]*href="([^"]+)"/.exec(e);
      const doiM  = /<arxiv:doi[^>]*>([^<]+)<\/arxiv:doi>/.exec(e);
      const authors = [...e.matchAll(/<name>([^<]+)<\/name>/g)].map(m => m[1]);
      const arxivIdM = idM ? /arxiv\.org\/abs\/([^\s"]+?)(v\d+)?$/.exec(idM[1]) : null;
      push({
        source: 'arxiv',
        source_id: arxivIdM ? arxivIdM[1] : (idM ? idM[1] : ''),
        arxiv_id: arxivIdM ? arxivIdM[1] : undefined,
        doi: doiM ? doiM[1] : undefined,
        title: (ttlM ? ttlM[1] : '').replace(/\s+/g, ' ').trim(),
        abstract: (sumM ? sumM[1] : '').trim(),
        authors,
        published_at: pubM ? pubM[1].slice(0,10) : undefined,
        venue: 'arXiv',
        url: htmlM ? htmlM[1] : (idM ? idM[1] : undefined),
        pdf_url: pdfM ? pdfM[1] : undefined,
        citations: 0
      });
    }
    continue;
  }
  // --- Semantic Scholar ---
  if (data && Array.isArray(data.data)) {
    for (const p of data.data) {
      push({
        source: 'semantic_scholar',
        source_id: p.paperId,
        doi: p.externalIds?.DOI?.toLowerCase(),
        arxiv_id: p.externalIds?.ArXiv,
        title: (p.title || '').trim(),
        abstract: (p.abstract || '').trim(),
        authors: (p.authors || []).map(a => a?.name).filter(Boolean),
        published_at: p.publicationDate || (p.year ? `${p.year}-01-01` : undefined),
        venue: p.venue,
        url: p.url,
        pdf_url: p.openAccessPdf?.url,
        citations: p.citationCount ?? 0
      });
    }
    continue;
  }
  // --- ChemRxiv ---
  if (data && (data.itemHits || data.items)) {
    const items = data.itemHits ?? data.items;
    for (const hit of items) {
      const item = hit.item || hit;
      if (!item?.id) continue;
      const authors = (item.authors || []).map(a => [a.firstName, a.lastName].filter(Boolean).join(' '));
      push({
        source: 'chemrxiv',
        source_id: String(item.id),
        doi: item.doi ? String(item.doi).toLowerCase() : undefined,
        title: (item.title || '').trim(),
        abstract: (item.abstract || '').trim(),
        authors,
        published_at: item.publishedDate ? item.publishedDate.slice(0,10) : undefined,
        venue: 'ChemRxiv',
        url: `https://chemrxiv.org/engage/chemrxiv/article-details/${item.id}`,
        pdf_url: item.asset?.original?.url,
        citations: 0
      });
    }
  }
}

// 중복 제거
const seen = new Set();
const uniq = [];
for (const p of out) {
  const key = p.doi ? `doi:${p.doi}` : (p.arxiv_id ? `arxiv:${p.arxiv_id}` : `${p.source}:${p.source_id}`);
  if (seen.has(key)) continue;
  seen.add(key);
  uniq.push(p);
}

// 최대 300 건으로 제한 (일일 목표)
return uniq.slice(0, 300).map(json => ({ json }));

// 실행 요약
const items = $input.all();
const summary = items.reduce((acc, it) => {
  const r = it.json || {};
  acc.batches += 1;
  acc.ingested += r.ingested ?? 0;
  acc.failed   += r.failed ?? 0;
  return acc;
}, { batches: 0, ingested: 0, failed: 0 });
return [{ json: summary }];
